 * @returns A promise that resolves to the player's email data, or null if not found
 */
async getEmailDataById(id: number): Promise<PlayerEmailDataDisplayType | null> {
    const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
    const player = await prisma.player.findUnique({
        where,
        select: {
            id: true,
            name: true,
            anonymous: true,
            accountEmail: true,
            extraEmails: {
                select: { email: true, verifiedAt: true },
                orderBy: [
                    { verifiedAt: 'desc' },
                    { createdAt: 'desc' },
                ],
            },
        },
    });
    if (!player) return null;

    const { id, name, anonymous, accountEmail, extraEmails } = player;
    return {
        id,
        name: this.getDisplayName({ id, name, anonymous }),
        accountEmail: accountEmail ?? null,
        extraEmails: mapExtraEmails(extraEmails),
    };
}

