'use client';

import {
    Anchor,
    Box,
    Button,
    Checkbox,
    Flex,
    RangeSlider,
    Switch,
    Table,
    Text,
    TextInput,
    Title,
    Tooltip,
} from '@mantine/core';
import { IconSortAscending, IconSortDescending } from '@tabler/icons-react';
import type { GameDayType } from 'prisma/zod/schemas/models/GameDay.schema';
import { useMemo, useState } from 'react';

import { PlayerTimeline } from '@/components/PlayerTimeline/PlayerTimeline';
import { PlayerWDLChart } from '@/components/PlayerWDLChart/PlayerWDLChart';
import { SendEmailForm } from '@/components/SendEmailForm/SendEmailForm';
import type { PlayerDataDisplayType } from '@/services/Player/Player';
import type { SendEmailProxy } from '@/types/actions/SendEmail';

export interface Props {
    players: PlayerDataType[];
    gameDay: GameDayType;
    sendEmail: SendEmailProxy;
}

export const PlayerList = ({ players, gameDay, sendEmail }: Props) => {
    const [sortBy, setSortBy] = useState<keyof PlayerDataType | null>('name');
    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('asc');
    const [filter, setFilter] = useState('');
    const [active, setActive] = useState(true);
    const [replyRange, setReplyRange] = useState<[number, number]>([0, gameDay.id]);
    const [selectedPlayers, setSelectedPlayers] = useState<PlayerDataType[]>([]);
    const [modalOpened, setModalOpened] = useState(false);

    const handleSort = (key: keyof PlayerDataType) => {
        if (sortBy === key) {
            setSortOrder((prev) => (prev === 'asc' ? 'desc' : 'asc'));
        } else {
            setSortBy(key);
            setSortOrder('asc');
        }
    };

    const handleSelectPlayer = (player: PlayerDataType) => {
        if (selectedPlayers.includes(player)) {
            setSelectedPlayers((prev) => prev.filter((p) => player !== p));
        } else {
            setSelectedPlayers((prev) => [...prev, player]);
        }
    };

    const filteredPlayers = players?.filter((player) => {
        const searchTerm = filter.toLowerCase();
        const nameMatches = player.name?.toLowerCase().includes(searchTerm) ?? false;
        const emailMatches = [player.accountEmail, ...player.extraEmails.map((playerEmail) => playerEmail.email)]
            .filter((playerEmail): playerEmail is string => !!playerEmail)
            .some((playerEmail) => playerEmail.toLowerCase().includes(searchTerm));
        const searchResult = nameMatches || emailMatches;

        return searchResult && (!active || player.finished === null);
    }) || [];

    const playersRepliedSince = filteredPlayers.filter((player) => {
        if (!player.lastResponded) {
            return (replyRange[1] === gameDay.id);
        }
        else {
            const repliedAfter = (gameDay.id - player.lastResponded) >= replyRange[0];
            const repliedBefore = (gameDay.id - player.lastResponded) <= replyRange[1];

            return repliedAfter && repliedBefore;
        }
    });

    const sortedPlayers = playersRepliedSince ? [...playersRepliedSince].sort((a, b) => {
        if (!sortBy) return 0;

        const aValue = a[sortBy];
        const bValue = b[sortBy];

        if (typeof aValue === 'number' || typeof bValue === 'number') {
            /* v8 ignore next 3 -- defensive fallback when a numeric sort field is unexpectedly nullish */
            const naValue = aValue as number || 0;
            const nbValue = bValue as number || 0;

            return sortOrder === 'asc' ? naValue - nbValue : nbValue - naValue;
        }

        if (typeof aValue === 'string' && typeof bValue === 'string') {
            return sortOrder === 'asc' ?
                aValue.localeCompare(bValue) :
                bValue.localeCompare(aValue);
        }

        if (aValue instanceof Date && bValue instanceof Date) {
            return sortOrder === 'asc' ?
                aValue.getTime() - bValue.getTime() :
                bValue.getTime() - aValue.getTime();
        }

        return 0;
    }) :
        /* v8 ignore next -- filter always returns an array, so this fallback is a defensive backstop */
        [];

    /**
     * Human-readable label describing whether we are showing only active players
     * or both active and former players, used in the main title text.
     */
    const activeStatusLabel = active ? 'Active Players' : 'Active and Former Players';

    /** Formats a RangeSlider thumb value as a human-readable week count label. */
    const rangeSliderLabel = (value: number) => `${value} weeks`;
    /**
     * Updates the reply-range filter from the RangeSlider.
     * @param range - A [min, max] tuple of weeks-ago values matching the heading text.
     */
    const handleRangeChange = (range: [number, number]) => setReplyRange(range);
    const selectedEmailPlayers = useMemo(
        () => selectedPlayers.map(({ id, name, accountEmail, extraEmails }) => ({ id, name, accountEmail, extraEmails })),
        [selectedPlayers],
    );

    /** Opens the send-email modal for the currently selected players. */
    const handleOpenEmailModal = () => setModalOpened(true);
    /** Closes the send-email modal. */
    const handleCloseEmailModal = () => setModalOpened(false);

    return (
        <Box>
            <Title order={1}>{sortedPlayers.length} {activeStatusLabel}</Title>
            <Title order={3}>who last responded between {replyRange[0]} and {replyRange[1]} weeks ago</Title>
            <TextInput
                mt={20}
                mb={20}
                placeholder="Search players"
                value={filter}
                onChange={(event) => setFilter(event.currentTarget.value)}
            />
            <Switch
                mt={20}
                mb={20}
                checked={active}
                onChange={(event) => setActive(event.currentTarget.checked)}
                color="blue"
                label="Active"
            />
            <Text size="sm">Last Response Range</Text>
            <RangeSlider
                label={rangeSliderLabel}
                min={0}
                max={gameDay.id}
                step={1}
                value={replyRange}
                onChange={handleRangeChange}
            />
            <Checkbox
                mt={20}
                mb={20}
                label="Select All"
                checked={selectedPlayers.length === sortedPlayers.length && sortedPlayers.length > 0}
                onChange={(event) => {
                    if (event.currentTarget.checked) {
                        setSelectedPlayers(sortedPlayers);
                    } else {
                        setSelectedPlayers([]);
                    }
                }}
            />
            <Text size="sm">Selected: {selectedPlayers.length}</Text>
            <Tooltip label="Send an email to the selected players">
                <Button
                    disabled={selectedPlayers.length === 0}
                    onClick={handleOpenEmailModal}
                >
                    Send Email...
                </Button>
            </Tooltip>
            <SendEmailForm
                players={selectedEmailPlayers}
                opened={modalOpened}
                onClose={handleCloseEmailModal}
                onSendEmail={sendEmail}
            />

            <Table mt={20}>
                <Table.Thead>
                    <Table.Tr>
                        <Table.Th>
                            Select
                        </Table.Th>
                        <Table.Th style={{ cursor: 'pointer' }} onClick={() => handleSort('name')}>
                            <Flex align="center" gap="xs">
                                Name
                                {sortBy === 'name' ? (sortOrder === 'asc' ? <IconSortAscending /> : <IconSortDescending />) : ''}
                            </Flex>
                        </Table.Th>
                        <Table.Th>
                            W-D-L
                        </Table.Th>
                        <Table.Th>
                            Timeline
                        </Table.Th>
                    </Table.Tr>
                </Table.Thead>
                <Table.Tbody>
                    {sortedPlayers.map((player) => (
                        <Table.Tr key={player.id}>
                            <Table.Td>
                                <Checkbox
                                    checked={selectedPlayers.includes(player)}
                                    onChange={() => handleSelectPlayer(player)}
                                />
                            </Table.Td>
                            <Table.Td>
                                <Anchor href={`/footy/player/${encodeURIComponent(player.id || "")}`}>
                                    {player.name}
                                </Anchor>
                            </Table.Td>
                            <Table.Td>
                                <PlayerWDLChart player={player} />
                            </Table.Td>
                            <Table.Td>
                                <PlayerTimeline player={player} currentGameId={gameDay.id} />
                            </Table.Td>
                        </Table.Tr>
                    ))}
                </Table.Tbody>
            </Table>
        </Box>
    );
};

'use client';

import { Button, Group, Modal, Text, TextInput, Tooltip } from '@mantine/core';
import { notifications } from '@mantine/notifications';
import { Link, RichTextEditor } from '@mantine/tiptap';
import { IconAlertTriangle, IconCheck, IconUser } from '@tabler/icons-react';
import Highlight from '@tiptap/extension-highlight';
import Placeholder from '@tiptap/extension-placeholder';
import TextAlign from '@tiptap/extension-text-align';
import Underline from '@tiptap/extension-underline';
import { useEditor } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import { useState } from 'react';

import { config } from '@/lib/config';
import { normalizeEmail } from '@/lib/email/normalizeEmail';
import { toPublicMessage } from '@/lib/errors';
import { captureUnexpectedError } from '@/lib/observability/sentry';
import { PlayerEmailDataDisplayType } from '@/types';
import { SendEmailProxy } from '@/types/actions/SendEmail';

import classes from './SendEmailForm.module.css';

export interface Props {
    opened: boolean;
    onClose: () => void;
    players: PlayerEmailDataType[];
    onSendEmail: SendEmailProxy;
    withinPortal?: boolean;
    withOverlay?: boolean;
}

export const SendEmailForm = ({
    opened,
    onClose,
    players,
    onSendEmail,
    withinPortal,
    withOverlay,
}: Props) => {
    const [subject, setSubject] = useState('');
    const names = players.map(({ name }) => name).filter((name): name is string => name != null).join(', ');
    const emails = Array.from(new Set(players.flatMap((player) => {
        const verifiedExtraEmails = player.extraEmails.filter((playerEmail) => playerEmail.verified);
        const preferredExtraEmails = verifiedExtraEmails.length > 0 ? verifiedExtraEmails : player.extraEmails;
        return [player.accountEmail, ...preferredExtraEmails.map((playerEmail) => playerEmail.email)];
    }).map(normalizeEmail).filter((email) => email.length > 0))).join(',');

    const editor = useEditor({
        extensions: [
            Highlight,
            Link,
            Placeholder.configure({ placeholder: 'Message text' }),
            StarterKit,
            TextAlign.configure({ types: ['heading', 'paragraph'] }),
            Underline,
        ],
        content: '',
        immediatelyRender: false,
    });

    if (!editor) return null;

    const handleSubmit = async () => {
        const id = notifications.show({
            loading: true,
            title: 'Sending email',
            message: 'Sending email...',
            autoClose: false,
            withCloseButton: false,
        });

        try {
            await onSendEmail({
                to: emails,
                subject,
                html: editor.getHTML(),
            });

            onClose();
            notifications.update({
                id,
                color: 'teal',
                title: 'Email sent',
                message: 'Email sent successfully',
                icon: <IconCheck size={config.notificationIconSize} />,
                loading: false,
                autoClose: config.notificationAutoClose,
            });
        } catch (err) {
            captureUnexpectedError(err, {
                layer: 'client',
                component: 'SendEmailForm',
                action: 'sendEmail',
                route: '/footy/admin/players',
                extra: {
                    recipientCount: players.length,
                },
            });
            notifications.update({
                id,
                color: 'red',
                title: 'Error',
                message: toPublicMessage(err, 'Failed to send email.'),
                icon: <IconAlertTriangle size={config.notificationIconSize} />,
                loading: false,
                autoClose: config.notificationAutoClose,
            });
        }
    };

    return (
        <Modal
            opened={opened}
            onClose={onClose}
            title="Send Mail to Players"
            size="lg"
            withinPortal={withinPortal}
            withOverlay={withOverlay}
        >
            <Tooltip label={names} multiline>
                <Text size="sm" mt="sm" lineClamp={1}>
                    <IconUser size={16} className={classes.users} />
                    <strong>To:</strong> {names}
                </Text>
            </Tooltip>
            <form onSubmit={(e) => { e.preventDefault(); void handleSubmit(); }}>
                <TextInput
                    label="Subject"
                    value={subject}
                    onChange={(event) => setSubject(event.currentTarget.value)}
                    required
                    mt="md"
                />

                <RichTextEditor editor={editor} mt="md">
                    <RichTextEditor.Toolbar sticky stickyOffset={60}>
                        <RichTextEditor.ControlsGroup>
                            <RichTextEditor.Bold />
                            <RichTextEditor.Italic />
                            <RichTextEditor.Underline />
                            <RichTextEditor.Strikethrough />
                            <RichTextEditor.ClearFormatting />
                            <RichTextEditor.Highlight />
                            <RichTextEditor.Code />
                        </RichTextEditor.ControlsGroup>

                        <RichTextEditor.ControlsGroup>
                            <RichTextEditor.H1 />
                            <RichTextEditor.H2 />
                            <RichTextEditor.H3 />
                            <RichTextEditor.H4 />
                        </RichTextEditor.ControlsGroup>

                        <RichTextEditor.ControlsGroup>
                            <RichTextEditor.Blockquote />
                            <RichTextEditor.Hr />
                            <RichTextEditor.BulletList />
                            <RichTextEditor.OrderedList />
                        </RichTextEditor.ControlsGroup>

                        <RichTextEditor.ControlsGroup>
                            <RichTextEditor.Link />
                            <RichTextEditor.Unlink />
                        </RichTextEditor.ControlsGroup>

                        <RichTextEditor.ControlsGroup>
                            <RichTextEditor.AlignLeft />
                            <RichTextEditor.AlignCenter />
                            <RichTextEditor.AlignJustify />
                            <RichTextEditor.AlignRight />
                        </RichTextEditor.ControlsGroup>
                    </RichTextEditor.Toolbar>

                    <RichTextEditor.Content />
                </RichTextEditor>

                <Group justify="flex-end" mt="md">
                    <Button type="submit">Send Mail</Button>
                </Group>
            </form>
        </Modal>
    );
};

