26	class PlayerService {
27	    /**
28	     * Gets the display name for a player.
29	     *
30	     * If the player is anonymous (i.e., the `anonymous` flag is `true`),
31	     * returns a generic name with the player ID. Otherwise, returns the
32	     * player's trimmed name, falling back to a generic name if the name is
33	     * empty or null. A `null` value for `anonymous` is treated as not anonymous
34	     * (equivalent to `false`).
35	     *
36	     * @param player - The player object containing id, name, and anonymous flag
37	     * @param player.id - The unique identifier for the player
38	     * @param player.name - The player's name, can be null
39	     * @param player.anonymous - Whether the player is anonymous; `true` marks
40	     * the player as anonymous, while `false` or a `null` value are treated as
41	     * not anonymous
42	     * @returns The display name for the player
43	     */
44	    private getDisplayName(player: { id: number; name: string | null; anonymous: boolean | null }) {
45	        if (player.anonymous) {
46	            return `Player ${player.id}`;
47	        }
48	
49	        return player.name?.trim() ?? `Player ${player.id}`;
50	    }
51	
52	    /**
53	    * Sanitizes a player object by replacing its name with a display name.
54	    *
55	    * @template T - The player object type extending an object with `id`,
56	    * `name`, and `anonymous` properties.
57	    * @param player - The player object to sanitize.
58	    * @returns A new object with the same properties as the input player, but
59	    * with the `name` property replaced by the display name (guaranteed to be a
60	    * string, not null).
61	    */
62	    private sanitizePlayerName<T extends { id: number; name: string | null; anonymous: boolean | null }>(
63	        player: T,
64	    ): Omit<T, 'name'> & { name: string } {
65	        return {
66	            ...player,
67	            name: this.getDisplayName(player),
68	        };
69	    }
70	
71	    /**
72	     * Get a single player by id
73	     * @param id The numeric ID for the player
74	     * @returns A promise that resolves to the player or undefined if none was
75	     * found
76	     */
77	    async getById(id: number): Promise<PlayerDisplayType | null> {
78	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
79	        const player = await prisma.player.findUnique({ where });
80	        return player ? this.sanitizePlayerName(player) : null;
81	    }
82	
83	    /**
84	     * Get a single player's email contact data by id.
85	     * @param id The numeric ID for the player
86	     * @returns A promise that resolves to the player's email data, or null if not found
87	     */
88	    async getEmailDataById(id: number): Promise<PlayerEmailDataDisplayType | null> {
89	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
90	        const player = await prisma.player.findUnique({
91	            where,
92	            select: {
93	                id: true,
94	                name: true,
95	                anonymous: true,
96	                accountEmail: true,
97	                extraEmails: {
98	                    select: { email: true, verifiedAt: true },
99	                    orderBy: [
100	                        { verifiedAt: 'desc' },
101	                        { createdAt: 'desc' },
102	                    ],
103	                },
104	            },
105	        });
106	        if (!player) return null;
107	
108	        return {
109	            id: player.id,
110	            name: this.getDisplayName(player),
111	            accountEmail: player.accountEmail ?? null,
112	            extraEmails: mapExtraEmails(player.extraEmails),
113	        };
114	    }
